1	<script setup lang="ts">
2	import { ref, onMounted, computed } from 'vue'
3	import { useSnippetStore } from '@/stores/snippet'
4	import CodeEditor from '@/components/common/CodeEditor.vue'
5	import CodeBlock from '@/components/common/CodeBlock.vue'
6	import type { CodeSnippet } from '@/types'
7	import {
8	  Search,
9	  Plus,
10	  Edit,
11	  Delete,
12	  Download,
13	  Upload,
14	} from '@element-plus/icons-vue'
15	import { ElMessageBox } from 'element-plus'
16	
17	const snippetStore = useSnippetStore()
18	
19	const showDialog = ref(false)
20	const dialogMode = ref<'create' | 'edit'>('create')
21	const editingSnippet = ref<Partial<CodeSnippet>>({
22	  title: '',
23	  code: '',
24	  language: 'javascript',
25	  description: '',
26	  tags: [],
27	})
28	const tagInput = ref('')
29	const fileInputRef = ref<HTMLInputElement | null>(null)
30	
31	const languages = [
32	  'javascript', 'typescript', 'python', 'java', 'go', 'rust',
33	  'c', 'cpp', 'csharp', 'php', 'ruby', 'swift', 'kotlin',
34	  'sql', 'html', 'css', 'scss', 'shell', 'yaml', 'json',
35	  'markdown', 'xml', 'plaintext',
36	]
37	
38	onMounted(() => {
39	  snippetStore.loadSnippets()
40	})
41	
42	function handleSearch() {
43	  snippetStore.filters.page = 1
44	  snippetStore.loadSnippets()
45	}
46	
47	function handlePageChange(page: number) {
48	  snippetStore.filters.page = page
49	  snippetStore.loadSnippets()
50	}
51	
52	function openCreateDialog() {
53	  dialogMode.value = 'create'
54	  editingSnippet.value = {
55	    title: '',
56	    code: '',
57	    language: 'javascript',
58	    description: '',
59	    tags: [],
60	  }
61	  showDialog.value = true
62	}
63	
64	function openEditDialog(snippet: CodeSnippet) {
65	  dialogMode.value = 'edit'
66	  editingSnippet.value = { ...snippet, tags: [...snippet.tags] }
67	  showDialog.value = true
68	}
69	
70	async function handleSave() {
71	  if (!editingSnippet.value.title?.trim() || !editingSnippet.value.code?.trim()) return
72	
73	  if (dialogMode.value === 'create') {
74	    await snippetStore.createSnippet(editingSnippet.value)
75	  } else {
76	    await snippetStore.updateSnippet(editingSnippet.value.id!, editingSnippet.value)
77	  }
78	  showDialog.value = false
79	}
80	
81	async function handleDelete(snippet: CodeSnippet) {
82	  try {
83	    await ElMessageBox.confirm(`确定删除代码片段"${snippet.title}"吗？`, '提示', {
84	      confirmButtonText: '确定',
85	      cancelButtonText: '取消',
86	      type: 'warning',
87	    })
88	    await snippetStore.deleteSnippet(snippet.id)
89	  } catch {
90	    // Cancelled
91	  }
92	}
93	
94	function addTag() {
95	  const tag = tagInput.value.trim()
96	  if (tag && !editingSnippet.value.tags?.includes(tag)) {
97	    if (!editingSnippet.value.tags) {
98	      editingSnippet.value.tags = []
99	    }
100	    editingSnippet.value.tags.push(tag)
101	    tagInput.value = ''
102	  }
103	}
104	
105	function removeTag(tag: string) {
106	  if (editingSnippet.value.tags) {
107	    editingSnippet.value.tags = editingSnippet.value.tags.filter((t) => t !== tag)
108	  }
109	}
110	
111	function handleExport() {
112	  snippetStore.exportAll()
113	}
114	
115	function handleImportClick() {
116	  fileInputRef.value?.click()
117	}
118	
119	function handleFileChange(event: Event) {
120	  const target = event.target as HTMLInputElement
121	  const file = target.files?.[0]
122	  if (file) {
123	    snippetStore.importFile(file)
124	    target.value = ''
125	  }
126	}
127	
128	const dialogTitle = computed(() => (dialogMode.value === 'create' ? '新建代码片段' : '编辑代码片段'))
129	</script>
130	
131	<template>
132	  <div class="snippets-view">
133	    <!-- Toolbar -->
134	    <div class="toolbar">
135	      <div class="toolbar-left">
136	        <el-input
137	          v-model="snippetStore.filters.keyword"
138	          placeholder="搜索代码片段..."
139	          :prefix-icon="Search"
140	          clearable
141	          style="width: 240px"
142	          @keyup.enter="handleSearch"
143	          @clear="handleSearch"
144	        />
145	        <el-select
146	          v-model="snippetStore.filters.language"
147	          placeholder="语言"
148	          clearable
149	          style="width: 140px"
150	          @change="handleSearch"
151	        >
152	          <el-option v-for="lang in languages" :key="lang" :label="lang" :value="lang" />
153	        </el-select>
154	        <el-button @click="handleSearch">搜索</el-button>
155	      </div>
156	      <div class="toolbar-right">
157	        <el-button :icon="Download" @click="handleExport">导出</el-button>
158	        <el-button :icon="Upload" @click="handleImportClick">导入</el-button>
159	        <input ref="fileInputRef" type="file" accept=".json" style="display: none" @change="handleFileChange" />
160	        <el-button type="primary" :icon="Plus" @click="openCreateDialog">新建</el-button>
161	      </div>
162	    </div>
163	
164	    <!-- Snippet List -->
165	    <div class="snippet-list" v-loading="snippetStore.loading">
166	      <div v-if="snippetStore.snippets.length === 0" class="empty-state">
167	        <el-empty description="暂无代码片段">
168	          <el-button type="primary" @click="openCreateDialog">创建第一个片段</el-button>
169	        </el-empty>
170	      </div>
171	      <div v-else class="snippet-grid">
172	        <div v-for="snippet in snippetStore.snippets" :key="snippet.id" class="snippet-card">
173	          <div class="snippet-header">
174	            <h4 class="snippet-title">{{ snippet.title }}</h4>
175	            <div class="snippet-actions">
176	              <el-button :icon="Edit" text size="small" @click="openEditDialog(snippet)" />
177	              <el-button :icon="Delete" text size="small" type="danger" @click="handleDelete(snippet)" />
178	            </div>
179	          </div>
180	          <p v-if="snippet.description" class="snippet-desc">{{ snippet.description }}</p>
181	          <div class="snippet-code">
182	            <CodeBlock :code="snippet.code" :language="snippet.language" />
183	          </div>
184	          <div class="snippet-footer">
185	            <div class="snippet-tags">
186	              <el-tag v-for="tag in snippet.tags" :key="tag" size="small" type="info">{{ tag }}</el-tag>
187	            </div>
188	            <span class="snippet-meta">
189	              {{ snippet.language }} | 使用 {{ snippet.useCount }} 次
190	            </span>
191	          </div>
192	        </div>
193	      </div>
194	
195	      <!-- Pagination -->
196	      <div v-if="snippetStore.total > snippetStore.filters.size" class="pagination">
197	        <el-pagination
198	          background
199	          layout="prev, pager, next"
200	          :total="snippetStore.total"
201	          :page-size="snippetStore.filters.size"
202	          :current-page="snippetStore.filters.page"
203	          @current-change="handlePageChange"
204	        />
205	      </div>
206	    </div>
207	
208	    <!-- Create/Edit Dialog - 修改后的部分 -->
209	    <!-- Create/Edit Dialog -->
210	<el-dialog
211	  v-model="showDialog"
212	  :title="dialogTitle"
213	  width="1000px"
214	  :close-on-click-modal="false"
215	  top="5vh"
216	>
217	  <el-form label-position="top">
218	    <el-form-item label="标题" required>
219	      <el-input v-model="editingSnippet.title" placeholder="代码片段标题" />
220	    </el-form-item>
221	
222	    <el-form-item label="语言">
223	      <el-select v-model="editingSnippet.language" placeholder="选择语言" style="width: 100%">
224	        <el-option v-for="lang in languages" :key="lang" :label="lang" :value="lang" />
225	      </el-select>
226	    </el-form-item>
227	
228	    <el-form-item label="代码" required>
229	      <CodeEditor 
230	        v-model="editingSnippet.code"
231	        :language="editingSnippet.language || 'javascript'"
232	        height="450px"
233	        width="100%"
234	      />
235	    </el-form-item>
236	
237	    <el-form-item label="描述">
238	      <el-input v-model="editingSnippet.description" type="textarea" :rows="4" placeholder="简要描述..." />
239	    </el-form-item>
240	
241	    <el-form-item label="标签">
242	      <div class="tag-editor">
243	        <el-tag
244	          v-for="tag in editingSnippet.tags"
245	          :key="tag"
246	          closable
247	          size="default"
248	          @close="removeTag(tag)"
249	        >
250	          {{ tag }}
251	        </el-tag>
252	        <el-input
253	          v-model="tagInput"
254	          size="small"
255	          style="width: 120px"
256	          placeholder="添加标签"
257	          @keyup.enter="addTag"
258	        />
259	      </div>
260	    </el-form-item>
261	  </el-form>
262	
263	  <template #footer>
264	    <el-button @click="showDialog = false">取消</el-button>
265	    <el-button
266	      type="primary"
267	      :disabled="!editingSnippet.title?.trim() || !editingSnippet.code?.trim()"
268	      @click="handleSave"
269	    >
270	      保存
271	    </el-button>
272	  </template>
273	</el-dialog>
274	  </div>
275	</template>
276	
